+/// NIP-04 encrypted direct message event kind.
+pub const NIP04_KIND_ENCRYPTED_DM: u64 = 4;
+
+/// NIP-44 gift-wrapped event kind (used for newer encrypted DMs).
+pub const NIP44_KIND_GIFT_WRAP: u64 = 1059;
+
